    i INT;
    bio_idx INT;
    p1_idx INT;
    p2_idx INT;
    p3_idx INT;
    user_rec RECORD;
BEGIN
    i := 1;
    FOR user_rec IN SELECT user_id FROM profiles ORDER BY user_id LOOP
        bio_idx := 1 + ((i - 1) % array_length(long_bios, 1));
        p1_idx := 1 + ((i - 1) % array_length(prompt_questions, 1));
        p2_idx := 1 + (i % array_length(prompt_questions, 1));
        p3_idx := 1 + ((i + 1) % array_length(prompt_questions, 1));

        UPDATE profiles
        SET
            bio = long_bios[bio_idx],
            prompts = jsonb_build_array(
                jsonb_build_object('id', 'prompt_' || i || '_1', 'question', prompt_questions[p1_idx], 'answer', prompt_answers[1 + ((i - 1) % array_length(prompt_answers, 1))]),
                jsonb_build_object('id', 'prompt_' || i || '_2', 'question', prompt_questions[p2_idx], 'answer', prompt_answers[1 + (i % array_length(prompt_answers, 1))]),
                jsonb_build_object('id', 'prompt_' || i || '_3', 'question', prompt_questions[p3_idx], 'answer', prompt_answers[1 + ((i + 1) % array_length(prompt_answers, 1))])
            )
        WHERE user_id = user_rec.user_id;

        i := i + 1;
    END LOOP;
END $$;
